import{_ as t,o as a,c as r,a0 as o}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Approve Registration Requests","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/approve-registrations.md","filePath":"how-to/approve-registrations.md"}'),s={name:"how-to/approve-registrations.md"};function i(n,e,l,h,u,d){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="approve-registration-requests" tabindex="-1">Approve Registration Requests <a class="header-anchor" href="#approve-registration-requests" aria-label="Permalink to &quot;Approve Registration Requests&quot;">​</a></h1><p>Registration requests are for people who asked for access from the public sign-up flow. Your job is to review each request, decide whether it should move forward, and place the new user in the right kingdom, alliance, and role.</p><blockquote><p>Screenshot placeholder: admin-registration.png</p></blockquote><h2 id="open-the-queue" tabindex="-1">Open the queue <a class="header-anchor" href="#open-the-queue" aria-label="Permalink to &quot;Open the queue&quot;">​</a></h2><ol><li>Open <strong>Admin</strong>.</li><li>Select <strong>Registration requests</strong>.</li></ol><p>The queue shows the requester&#39;s server, player name, email, profile ID, alliance tag, requested role, message, status, and created time.</p><h2 id="your-three-main-actions" tabindex="-1">Your three main actions <a class="header-anchor" href="#your-three-main-actions" aria-label="Permalink to &quot;Your three main actions&quot;">​</a></h2><ul><li><strong>Approve</strong> when the request is valid and ready.</li><li><strong>Needs info</strong> when you want to pause it and ask for more clarity.</li><li><strong>Reject</strong> when the request should not be accepted.</li></ul><h2 id="approve-a-request" tabindex="-1">Approve a request <a class="header-anchor" href="#approve-a-request" aria-label="Permalink to &quot;Approve a request&quot;">​</a></h2><ol><li>Select <strong>Approve</strong> on a pending request.</li><li>Fill in the approval form. The form includes <strong>Username</strong>, <strong>Display name</strong>, <strong>Kingdom</strong>, <strong>Alliance</strong> when needed, <strong>Role</strong>, and <strong>Admin note</strong>.</li><li>Select <strong>Approve and create user</strong>.</li></ol><p>What happens next:</p><ul><li>The user account is created.</li><li>The assignment is created at the same time.</li><li>A temporary password is generated automatically.</li><li>If the request has an email address, that temporary password is emailed once to the requester.</li><li>The new user is forced to change it at first login.</li></ul><h2 id="when-to-use-needs-info" tabindex="-1">When to use &quot;Needs info&quot; <a class="header-anchor" href="#when-to-use-needs-info" aria-label="Permalink to &quot;When to use &quot;Needs info&quot;&quot;">​</a></h2><p>Use <strong>Needs info</strong> when the request is probably real but something important is unclear, such as:</p><ul><li>the wrong kingdom</li><li>a missing alliance choice</li><li>the wrong requested role</li><li>a message that needs manual checking</li></ul><h2 id="when-to-reject" tabindex="-1">When to reject <a class="header-anchor" href="#when-to-reject" aria-label="Permalink to &quot;When to reject&quot;">​</a></h2><p>Reject when the request should not be admitted. Keep the reasoning clear in your admin note if your team needs an audit trail later.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Match the role to the smallest access the person really needs.</li><li>Check whether the player belongs to a specific alliance before choosing the assignment.</li><li>If someone already has an account, do not approve the request as a brand-new user. Update the existing account instead.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../getting-started/registering.html">Request an Account</a></li><li><a href="./create-user.html">Create a User</a></li><li><a href="./assign-roles.html">Assign or Remove Roles</a></li></ul>',21)])])}const g=t(s,[["render",i]]);export{p as __pageData,g as default};
